console.log("pdf_informe.js cargado");

function formatearFechaISO(fechaISO) {
  if(!fechaISO) return "";
  const [anio, mes, dia] = fechaISO.split("-");
  return `${dia}/${mes}/${anio}`;
}

const raw = sessionStorage.getItem("informe_pdf");

if (!raw) {
  alert("No hay informe cargado");
} else {
  const informe = JSON.parse(raw);
  const logoBase64 = "data:image/png;base64,";


  console.log("Informe recibido:", informe);

  document.getElementById("cliente").textContent = informe.cliente ?? "";
  document.getElementById("numero").textContent = informe.numero ?? "";
  document.getElementById("tecnicos").textContent = informe.tecnicos ?? "";

  document.getElementById("equipoMarca").textContent =
    `${informe.equipo ?? ""} / ${informe.marca ?? ""}`;

  document.getElementById("modeloSerie").textContent =
    `${informe.modelo ?? ""} / ${informe.serie ?? ""}`;

  document.getElementById("motivo").textContent = informe.motivo ?? "";
  document.getElementById("tipoTrabajo").textContent = informe.tipoTrabajo ?? "";
  document.getElementById("presupuesto").textContent = informe.presupuesto ?? "";
  document.getElementById("fecha").textContent = informe.fechaFin ? formatearFechaISO(informe.fechaFin) : "";
  document.getElementById("horaInicio").textContent = informe.horaInicio ?? "";
  document.getElementById("horaFin").textContent = informe.horaFin ?? "";
  document.getElementById("servicio").textContent = informe.servicio ?? "";
  document.getElementById("obs").textContent = informe.obs ?? "";
  document.getElementById("recibido").textContent = informe.recibido ?? "";
  document.getElementById("status").textContent = informe.status ?? "";
  document.getElementById("repuesto").textContent = informe.repuestos ?? "";
  document.getElementById("logoEmpresa").src = logoBase64;

  if (informe.firma) {
    document.getElementById("firmaCliente").src = informe.firma;
  }

  if (informe.firmaT) {
    document.getElementById("firmaTecnico").src = informe.firmaT;
  }

  const ul = document.getElementById("listaLinks");
    ul.innerHTML = "";

  if (Array.isArray(informe.links)) {
    informe.links.forEach((link, i) => {
      const li = document.createElement("li");

      li.innerHTML = `
        <a href="${link}" target="_blank">
          Ver imagen ${i + 1}
        </a>
      `;

      ul.appendChild(li);
    });
  }
  

}